    @Test
    void testEquals_differentCommentMarker() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\',
                null, null, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '!', '\\',
                null, null, false, true, false, "\r\n");
