    @Test
    void testEquals_headerNonNullVsNull() throws Exception {
        String[] header = new String[] {"a", "b"};
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\',
                null, header, false, true, false, "\r\n");
