    }

    @Test
    void testEquals_ignoreSurroundingSpacesDiffers() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\',
                null, null, true, true, false, "\r\n");
